Extending the System

Adding New Column Types
To support a new column type in exports:

Add rendering logic in svg-generator.ts:

function renderTableRow(...) {
  // ...existing code...

  if (col.type === "myNewType") {
    // Render your custom SVG elements
    lines.push(`&lt;rect .../&gt;`);
  }
}

Rebuild both bundles:

bun run build


Customizing Export Options
The ExportOptions interface can be extended:
interface ExportOptions {
  width?: number;
  height?: number;
  scale?: number;
  backgroundColor?: string;
  // Add new options here
}

Type Checking Patterns

S7_inherits for Runtime Checks
# In modifiers.R
set_row_style &lt;- function(x, ...) {
  spec &lt;- if (inherits(x, "htmlwidget")) {
    attr(x, "webspec")
  } else if (S7_inherits(x, WebSpec)) {
    x
  } else {
    cli_abort("x must be a WebSpec or htmlwidget")
  }
  ...
}

# In columns.R
col_group &lt;- function(header, ...) {
  columns &lt;- list(...)
  for (i in seq_along(columns)) {
    if (!S7_inherits(columns[[i]], ColumnSpec)) {
      cli_abort("All arguments must be ColumnSpec objects")
    }
  }
  ...
}


class_any Escape Hatch
Some properties use class_any for flexibility:
# Allows NULL or WebTheme
theme = new_property(class_any, default = NULL)

# Allows numeric or "auto" string
width = new_property(class_any, default = NA_real_)

# Allows NULL or numeric vector
tick_values = new_property(class_any, default = NULL)
A more type-safe approach would use unions:
theme = new_property(
  new_union(WebTheme, class_missing),
  default = NULL
)

Method Dispatch
S7 methods are registered for generic functions:
# Print method for WebSpec
method(print, WebSpec) &lt;- function(x, ...) {
  cli_inform(c(
    "A {.cls WebSpec} with {nrow(x@data)} row{?s}",
    "*" = "Columns: {length(x@columns)}",
    "*" = "Groups: {length(x@groups)}"
  ))
  invisible(x)
}

# Plot method (renders as widget via forest_plot)
method(plot, WebSpec) &lt;- function(x, ...) {
  forest_plot(x, ...)
}

# as.data.frame method
method(as.data.frame, WebSpec) &lt;- function(x, ...) {
  x@data
}

Switch themes mid-Shiny-session
Use set_theme() on a proxy to re-skin without a full re-render.


Code
server &lt;- function(input, output, session) {
  output$plot &lt;- renderTabviz({
    tabviz(data, label = "study",
           columns = list(viz_forest("hr", "lower", "upper")))
  })

  observeEvent(input$theme, {
    tabviz_proxy("plot") |&gt; set_theme(input$theme)
  })
}

Filter via a slider in Shiny
Proxy-dispatched filter_rows() updates in place.


Code
ui &lt;- fluidPage(
  sliderInput("max_p", "Max p-value", min = 0, max = 1, value = 0.1),
  tabvizOutput("plot")
)

server &lt;- function(input, output, session) {
  output$plot &lt;- renderTabviz({ tabviz(data, ...) })

  observeEvent(input$max_p, {
    proxy &lt;- tabviz_proxy("plot")
    proxy |&gt;
      clear_filters() |&gt;
      filter_rows("pval", "lt", input$max_p)
  })
}

Preserve scroll/selection across proxy updates
Proxy verbs (sort_rows, filter_rows, update_column, etc.) mutate state in place and preserve scroll position, open groups, and selection. Avoid renderTabviz({ tabviz(...) }) for incremental changes — it re-renders the whole widget.


Code
# GOOD: incremental update keeps scroll/selection
observeEvent(input$sort_col, {
  tabviz_proxy("plot") |&gt; sort_rows(input$sort_col, "desc")
})

# BAD: full re-render loses scroll position
output$plot &lt;- renderTabviz({
  data |&gt;
    arrange(desc(.data[[input$sort_col]])) |&gt;
    tabviz(...)
})

Change a column’s header and width mid-session
Use update_column() via a proxy — no re-render, no spec rebuild.


Code
observeEvent(input$relabel, {
  tabviz_proxy("plot") |&gt;
    update_column("hr", header = "Hazard Ratio", width = 160)
})

Compose reusable styling pipelines
Wrap your organization’s standards in a function. Works on both WebSpec and htmlwidget inputs because every set_*() returns the same type it received.


Code
house_style &lt;- function(x) {
  x |&gt;
    set_marker_style(color = "direction_color") |&gt;
    set_row_style(bold = "is_primary", type = "row_type") |&gt;
    set_theme(web_theme_jama() |&gt;
                set_theme_field(c("axis", "gridlines"), TRUE) |&gt;
                set_theme_field(c("axis", "gridline_style"), "dotted"))
}

tabviz(trial_a, ...) |&gt; house_style()
tabviz(trial_b, ...) |&gt; house_style()

Tooltips
Tooltips are opt-in. Specify the column names you want to surface on marker hover:


Code
data(glp1_trials)

glp1_trials |&gt;
  filter(row_type == "data", group == "Main Trials") |&gt;
  head(4) |&gt;
  tabviz(label = "study",
    interaction = web_interaction(tooltip_fields = c("n", "events", "pvalue")),
    footnote = "Hover over markers to see tooltip",
    columns = list(
      viz_forest(point = "hr", lower = "lower", upper = "upper",
                 scale = "log", null_value = 1)
    )
  )






See Interactivity for the full set of web_interaction() controls.

Cell-level styling
All the cell-styling arguments (bold, italic, color, bg, badge, icon, emphasis, muted, accent) accept either a column name or a formula. See Cell Styling for the full formula-pronoun rules and recipes.


Code
glp1_trials |&gt;
  filter(row_type == "data", group == "Main Trials") |&gt;
  head(4) |&gt;
  mutate(
    is_sig   = upper &lt; 1,
    hr_color = ifelse(upper &lt; 1, "#166534", "#64748b")
  ) |&gt;
  tabviz(
    label = "study",
    columns = list(
      col_interval("hr", "lower", "upper", header = "HR (95% CI)",
                   bold = "is_sig", color = "hr_color"),
      col_pvalue("pvalue", "P", bold = "is_sig")
    )
  )

Customizing Interactions


Code
glp1_trials |&gt;
  filter(row_type == "data") |&gt;
  head(4) |&gt;
  tabviz(
    label = "study",
    columns = list(
      col_text("drug", "Drug"),
      viz_forest(point = "hr", lower = "lower", upper = "upper",
                 scale = "log", null_value = 1, width = 160)
    ),
    interaction = web_interaction(
      enable_sort = FALSE,
      enable_select = FALSE
    ),
    theme = web_theme_jama()
  )

Hover Tooltips
Add tooltips that appear when hovering over forest plot markers:


Code
glp1_trials |&gt;
  filter(row_type == "data") |&gt;
  head(4) |&gt;
  tabviz(
    label = "study",
    columns = list(
      viz_forest(point = "hr", lower = "lower", upper = "upper",
                 scale = "log", null_value = 1, width = 180),
      col_interval("hr", "lower", "upper", header = "HR (95% CI)")
    ),
    interaction = web_interaction(
      tooltip_fields = c("drug", "n", "events", "pvalue")
    ),
    theme = web_theme_jama(),
    footnote = "Hover over markers to see details"
  )






Tooltips show the values from the specified columns for each row.

View Source (v0.20+)
The &lt;/&gt; icon in the widget toolbar opens a three-tab panel showing the current widget as fluent R code:

Table ops — your original tabviz(...) call (captured as written) plus every interactive structural change you’ve made (resize / add / remove / move columns, move rows, cell / title / caption / footnote edits, paint stamps, theme switches, watermark, split-forest align-widths toggle).
Theme — the current theme state as a web_theme_*()  |&gt; set_*() chain. Identical to the “View theme source” panel that used to live inside the Settings sidebar.
Combined — both, stitched together:

mytheme &lt;- web_theme_cochrane() |&gt;
  set_inputs(brand = "#0891b2")

tbl &lt;- tabviz(dt, label = "study", columns = list(...), theme = mytheme) |&gt;
  resize_column("drug", 160) |&gt;
  move_column("drug", to = 2) |&gt;
  set_title("Updated")
The log is append-only: if you resize a column from 120 to 150 and back, both calls appear in order. No attempt is made to dedupe or optimize — the raw sequence is the history.
The corresponding fluent R functions are all exported from the package, so the emitted chain pastes into R as-is.

Step 3: Customize without rewriting
Three pipe-friendly modifiers cover the common edits:


Code
custom &lt;- web_theme_jama() |&gt;
  set_inputs(brand = "#1F3A5F", accent = "#B08938") |&gt;
  set_variants(density = "comfortable", header_style = "bold") |&gt;
  set_spacing(row_height = 28, axis_gap = 14)



set_inputs(theme, ...) — update Tier 1 inputs. Cascade-aware: changing brand clears brand_deep so it re-mirrors; changing series_anchors rebuilds the slot bundles.
set_variants(theme, ...) — flip per-table toggles (density / header_style / first_column_style). Density change resets spacing tokens so the new preset’s values flow through.
set_spacing(theme, ...) — per-token spacing override on top of the density preset. Set what you care about; the rest follow density.

For surgical overrides anywhere in the theme tree, use set_theme_field() with a path:


Code
custom &lt;- web_theme_cochrane() |&gt;
  set_theme_field(c("row_group", "L1", "bg"), "#EEEEEE") |&gt;
  set_theme_field(c("series", 1L, "fill"), "#FF0000") |&gt;
  set_theme_field(c("plot", "gridline"), "#003300") |&gt;
  set_theme_field(c("axis", "gridlines"), TRUE)


Path entries are property names (strings) or list indices (integers, currently only for series). The function re-resolves the theme before returning, so derived fields stay consistent with your override.

Pinning chrome separately from data
Because the cascades share only Tier 1, you can override a Tier 2 chrome role without disturbing the data marks, or vice versa:


Code
# Pin the surface to a specific cream, regardless of what neutrals say
web_theme_cochrane() |&gt;
  set_theme_field(c("surface", "base"), "#FDFCFB")

# Adjust series 2's stroke without affecting any other slot or chrome
web_theme_cochrane() |&gt;
  set_theme_field(c("series", 2L, "stroke"), "#444444")


Re-resolution preserves explicit overrides on subsequent edits — set_inputs(brand = "...") after the override above will refresh series colors but leave surface.base pinned to your cream.

Shiny Optimization

Debouncing Updates


Code
server &lt;- function(input, output, session) {
  # Debounce rapid filter changes
  filtered_data &lt;- reactive({
    input$filter
  }) |&gt; debounce(300)  # Wait 300ms after last change

  output$table &lt;- renderTabviz({
    tabviz(filtered_data(), ...)
  })
}




Proxy Updates
Use proxy for incremental updates instead of re-rendering:


Code
server &lt;- function(input, output, session) {
  output$table &lt;- renderTabviz({
    tabviz(initial_data, ...)
  })

  proxy &lt;- tabviz_proxy("table")

  observeEvent(input$sort_column, {
    sort_rows(proxy, input$sort_column, "asc")
  })

  observeEvent(input$filter, {
    filter_rows(proxy, "region", "eq", input$filter)
  })
}

Profiling

Identifying Bottlenecks


Code
library(profvis)

profvis({
  p &lt;- tabviz(large_data,
    label = "study",
    columns = list(
      col_sparkline("trend"),
      viz_forest(...)
    ),
    row_bold = ~ pval &lt; 0.05
  )
})




Timing Components


Code
# Time spec creation
system.time({
  spec &lt;- tabviz(data, ..., .spec_only = TRUE)
})

# Time widget creation
system.time({
  widget &lt;- forest_plot(spec)
})

# Time export
system.time({
  save_plot(widget, "output.svg")
})

Multiple effects (forest)
tabviz(data, label = "study", columns = list(
  viz_forest(
    effects = list(
      effect_forest("itt_hr", "itt_lo", "itt_hi", label = "ITT", color = "#2563eb"),
      effect_forest("pp_hr",  "pp_lo",  "pp_hi",  label = "Per-Protocol", color = "#16a34a")
    ),
    scale = "log", null_value = 1
  )
))
